import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.C6K0jwmI.js";const p=JSON.parse('{"title":"在庫・レシピ管理","description":"","frontmatter":{"title":"在庫・レシピ管理"},"headers":[],"relativePath":"tenant/11-inventory.md","filePath":"tenant/11-inventory.md"}'),o={name:"tenant/11-inventory.md"};function n(i,t,l,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="_11-在庫・レシピ管理" tabindex="-1">11. 在庫・レシピ管理 <a class="header-anchor" href="#_11-在庫・レシピ管理" aria-label="Permalink to &quot;11. 在庫・レシピ管理&quot;">​</a></h1><p>在庫・レシピ管理では、原材料、在庫数、使用量、棚卸し、AI需要予測を管理します。品切れ防止と仕入れ判断に役立ちます。</p><h2 id="原材料を登録する" tabindex="-1">原材料を登録する <a class="header-anchor" href="#原材料を登録する" aria-label="Permalink to &quot;原材料を登録する&quot;">​</a></h2><ol><li>原材料名、単位、現在庫、低在庫の目安を登録します。</li><li>仕入れ単価や保管場所を必要に応じて入力します。</li><li>棚卸し時に実在庫を更新します。</li></ol><h2 id="レシピを設定する" tabindex="-1">レシピを設定する <a class="header-anchor" href="#レシピを設定する" aria-label="Permalink to &quot;レシピを設定する&quot;">​</a></h2><p>商品ごとに使用する原材料と数量を登録します。注文数に応じて在庫を確認しやすくなります。</p><h2 id="棚卸し" tabindex="-1">棚卸し <a class="header-anchor" href="#棚卸し" aria-label="Permalink to &quot;棚卸し&quot;">​</a></h2><p>営業終了後や月末など、店舗の運用に合わせて棚卸しを行います。実在庫とシステム上の在庫がずれている場合は、理由を確認してください。</p><h2 id="ai需要予測" tabindex="-1">AI需要予測 <a class="header-anchor" href="#ai需要予測" aria-label="Permalink to &quot;AI需要予測&quot;">​</a></h2><p>過去の販売傾向をもとに、仕込みや発注の参考値を確認できます。天候、イベント、臨時休業など、システムに反映されない事情は店舗判断で調整してください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>在庫数が合わない</td><td>棚卸し、廃棄、仕入れ、手入力の履歴を確認してください。</td></tr><tr><td>品切れ表示が合わない</td><td>商品とレシピの紐づけ、低在庫の目安を確認してください。</td></tr><tr><td>需要予測が極端</td><td>休業日、イベント、異常値が含まれていないか確認してください。</td></tr><tr><td>CSVで文字化けする</td><td>UTF-8形式で保存してから取り込んでください。</td></tr></tbody></table>',12)])])}const b=a(o,[["render",n]]);export{p as __pageData,b as default};
